--
-- Table structure for table `reviews`
--

DROP TABLE IF EXISTS `reviews`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `reviews` (
  `review_id` int NOT NULL AUTO_INCREMENT,
  `telegram_id` bigint NOT NULL,
  `username` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `full_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `rating` int NOT NULL,
  `review_text` text COLLATE utf8mb4_unicode_ci,
  `photo_url` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `is_approved` tinyint(1) DEFAULT '0' COMMENT '0 - не одобрен, 1 - одобрен',
  `moderated_at` timestamp NULL DEFAULT NULL COMMENT 'Время одобрения отзыва',
  `moderated_by` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Telegram ID модератора, который одобрил отзыв',
  PRIMARY KEY (`review_id`),
  KEY `telegram_id` (`telegram_id`),
  KEY `created_at` (`created_at`),
  KEY `rating` (`rating`),
  KEY `idx_reviews_rating` (`rating`),
  KEY `idx_reviews_telegram_id_approved` (`telegram_id`),
  KEY `idx_reviews_created_at` (`created_at`),
  KEY `idx_reviews_approved` (`is_approved`),
  CONSTRAINT `reviews_ibfk_1` FOREIGN KEY (`telegram_id`) REFERENCES `users` (`telegram_id`) ON DELETE CASCADE,
  CONSTRAINT `reviews_chk_1` CHECK (((`rating` >= 1) and (`rating` <= 5)))
) ENGINE=InnoDB AUTO_INCREMENT=122 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `reviews`
--

LOCK TABLES `reviews` WRITE;
/*!40000 ALTER TABLE `reviews` DISABLE KEYS */;
INSERT INTO `reviews` VALUES (94,685895967,NULL,'Фёдор',5,'Форсы пришли очень быстро, все очень понравилось. Артему респект за быстрое оформление заказа и приятные цены, буду заказывать еще 💪🏻',NULL,'2024-12-12 17:21:00','2025-11-04 18:26:27',1,NULL,NULL),(95,881445662,'@ffilaaa',NULL,5,'заказывал тимбы, все четко и по делу, отдельное спасибо за оперативность',NULL,'2024-12-12 17:21:00','2025-11-04 18:26:27',1,NULL,NULL),(96,588673930,'@savelporokin',NULL,5,'Заказывал себе обувь на зиму, пришла без задержек и прочих неполадок. Общая сумма заказа на порядок ниже того, что могут предложить оффлайн магазины. Благодарен за качественное и оперативное исполнение заказа. Теперь буду пользоваться только этим сервисом, крайне рекомендую.',NULL,'2024-12-13 14:42:00','2025-11-04 18:26:27',1,NULL,NULL),(97,717120737,'@marksapozhnikov',NULL,5,'Заказывал через poizonic, реально крутой сервис. Доставили почти за две недели, и все прошло без проблем. Рекомендую',NULL,'2024-12-15 20:28:00','2025-11-04 18:26:27',1,NULL,NULL),(98,769042837,'@pashakhom',NULL,5,'Боты пришли быстро, даже быстрее чем ориентировочная дата. Коробка в порядке. Наценка совсем небольшая, за подобную услугу абсолютно оправданная цена. Спасибо, всем доволен)',NULL,'2024-12-21 07:43:00','2025-11-04 18:26:27',1,NULL,NULL),(99,848584135,'@ilya_achincev',NULL,5,'Спасибо большое за доставленную пару! Очень оперативно, отзывчивый менеджер, обязательно буду заказывать еще и еще!',NULL,'2025-01-11 18:39:00','2025-11-04 18:26:27',1,NULL,NULL),(100,229385394,'@kulizzka',NULL,5,'оперативная доставка без заморочек + сладкая цена не может не радовать, спасибо ребята, буду заказывать еще 😜',NULL,'2025-01-22 02:09:00','2025-11-04 18:26:27',1,NULL,NULL),(101,685895967,NULL,'Фёдор',5,'Уже второй раз заказываю в этом магазине. Джорданы пришли очень быстро, качество на высшем уровне',NULL,'2025-03-25 07:42:00','2025-11-04 18:26:27',1,NULL,NULL),(102,881445662,'@ffilaaa',NULL,5,'Сервис у poizonic как обычно на высоте, полный газ!💨 🚀',NULL,'2025-03-29 07:23:00','2025-11-04 18:26:27',1,NULL,NULL),(103,717120737,'@marksapozhnikov',NULL,5,'Спасибо, Артему! Все качественно четко привез. Буду заказывать еще',NULL,'2025-03-29 07:23:00','2025-11-04 18:26:27',1,NULL,NULL),(104,974171981,'@broken1ce23',NULL,5,'Заказывал штаны, качество бомба, доставка быстрая, всем рекомендую сервис🤙',NULL,'2025-04-21 09:17:00','2025-11-04 18:26:28',1,NULL,NULL),(105,769042837,'@pashakhom',NULL,5,'Кроссовки пришли достаточно быстро, и цена как всегда радует! Заказываю здесь уже второй раз и никаких проблем не возникло, буду заказывать еще)',NULL,'2025-04-22 11:35:00','2025-11-04 18:26:28',1,NULL,NULL),(106,848584135,'@ilya_achincev',NULL,5,'Спасибо за оперативность! Все доставлено в сроки, подошло размер в размер. Девушка довольна, будем заказывать еще!',NULL,'2025-05-15 13:21:00','2025-11-04 18:26:28',1,NULL,NULL),(107,523178359,'@avlovaa',NULL,5,'Спасибо за помощь в заказе poizonic! Всё оформили быстро и максимально понятно, ответили на интересующие вопросы. С доставкой тоже проблем не было, прислали трек номер, посылку отслеживала. Дошла за 3,5 недели, я довольна, советую сервис, буду обращаться ещё!👍💘',NULL,'2025-05-22 11:34:00','2025-11-04 18:26:28',1,NULL,NULL),(108,881445662,'@ffilaaa',NULL,5,'Poizonic🤝 Быстро, недорого, индивидуальный подход❗️',NULL,'2025-05-22 18:59:00','2025-11-04 18:26:28',1,NULL,NULL),(109,141391979,NULL,'Елизавета Белькова',5,'Посылка пришла вовремя, согласно оговоренного срока. Кроссовки упакованы в двух коробках, упаковка целая, не повреждена. Посылка соответствует тому, что заказывала. Кроссовки соответствуют указанному размеру, очень удобные. Покупкой довольна.',NULL,'2025-05-24 06:35:00','2025-11-04 18:26:28',1,NULL,NULL),(110,660119985,NULL,'Elnur',5,'Приветствую! Все пришло большое спасибо ! Будем обращаться 🤝',NULL,'2025-06-16 13:58:00','2025-11-04 18:26:28',1,NULL,NULL),(111,103178452,'@phaepich',NULL,5,'Спасибо пойзонику за низкую комиссию и быструю отправку! Заказывал 2 пары: палермы и спешиалы. Менеджер отвечал быстро, заказ оформили в тот же день. Через 22 дня пары уже были у меня. Короче, хорошие ребята с хорошей комиссией. Явно буду брать ещё',NULL,'2025-06-27 15:04:00','2025-11-04 18:26:28',1,NULL,NULL),(112,229385394,'@kulizzka',NULL,5,'мой любимый сервис 10/10 снова порадовал новым айтемом🤗 быстро четко как всегда мистер йе доволен',NULL,'2025-08-08 10:22:00','2025-11-04 18:26:28',1,NULL,NULL),(113,299660326,'@marrgiza',NULL,5,'Спасибо большое за кроссовки 👟 Все понравилось, помогли с выбором модели и размера, все подошло идеально! Также ответили на все мои вопросы и держали в курсе перемещений посылки Обязательно буду заказывать еще ❤️',NULL,'2025-08-24 18:00:00','2025-11-04 18:26:28',1,NULL,NULL),(114,490940975,'@nedashkevich_23',NULL,5,'Заказала биркенштоки через ребят — всё прошло максимально гладко! 🚀 Пришли быстро, без задержек, в оригинальной коробке, качество 🔝',NULL,'2025-08-31 08:42:00','2025-11-04 18:26:28',1,NULL,NULL),(115,143035898,NULL,'Freemelly',5,'Все прошло отлично. Помогли с размером, доставка быстрая, менеджер всегда был на связи. Никаких проблем с момента оформления заказа и до получения не было. Советую!!',NULL,'2025-09-19 08:19:00','2025-11-04 18:26:28',1,NULL,NULL),(116,970223501,'@happy_goga',NULL,5,'Выбрали, заказали, доставили. Всё быстро и просто. На протяжении всего времени была постоянная связь, менеджер уведомлял о каждом шаге. Однозначно рекомендую. Спасибо, poizonic!♥️🔥',NULL,'2025-10-06 13:24:00','2025-11-04 18:26:28',1,NULL,NULL),(117,244879858,'@pr0kh1',NULL,5,'Poizonic🤝 Быстро, недорого, индивидуальный подход❗️',NULL,'2025-11-04 18:04:00','2025-11-04 18:26:28',1,NULL,NULL),(118,588673930,'@savelporokin',NULL,5,'Заказывал кроссовки, пришли в срок, комплект без повреждений, все в порядке. Кроссовками доволен, сервис на высшем уровне, рекомендую',NULL,'2025-11-04 18:04:00','2025-11-04 18:26:28',1,NULL,NULL),(119,881445662,'@ffilaaa',NULL,5,'быстро, всегда на связи, как обычно все на высшем уровне🔝',NULL,'2025-11-04 18:04:00','2025-11-04 18:26:28',1,NULL,NULL),(120,123456789,'test_user','Test User',5,'Супер!','/uploads/reviews/review-1762371956365-138915087.png','2025-11-05 19:45:57','2025-11-05 20:23:47',1,'2025-11-05 20:23:47','admin'),(121,123456789,'test_user','Test User',5,'Класс','/uploads/reviews/review-1762378002463-21019352.mp4','2025-11-05 21:26:43','2025-11-05 21:27:14',1,'2025-11-05 21:27:14','admin');
