--
-- Table structure for table `users`
--

DROP TABLE IF EXISTS `users`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `users` (
  `telegram_id` bigint NOT NULL,
  `access_expires_at` timestamp NULL DEFAULT NULL,
  `referred_by` bigint DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `preferred_currency` varchar(3) COLLATE utf8mb4_unicode_ci DEFAULT 'RUB',
  `full_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `phone_number` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `username` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `avatar_url` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'URL аватарки пользователя из Telegram',
  `last_activity` timestamp NULL DEFAULT NULL,
  `commission` int DEFAULT '1000' COMMENT 'Комиссия в рублях (1000₽ по умолчанию, 400₽ для рефералов)',
  `xp` int DEFAULT '0' COMMENT 'Experience points for gamification',
  `current_level` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT 'Bronze' COMMENT 'Current level: Bronze, Silver, Gold, Platinum, Diamond',
  `last_daily_login` date DEFAULT NULL COMMENT 'Last daily login date for activity tracking',
  `login_streak` int DEFAULT '0' COMMENT 'Consecutive days login streak',
  `total_savings` decimal(10,2) DEFAULT '0.00' COMMENT 'Общая экономия пользователя',
  `temp_discount_active` tinyint(1) DEFAULT '0' COMMENT 'Активна ли временная скидка',
  `temp_discount_end_date` timestamp NULL DEFAULT NULL COMMENT 'Дата окончания временной скидки',
  `last_login_date` date DEFAULT NULL COMMENT 'Дата последнего входа',
  `total_logins` int DEFAULT '0' COMMENT 'Общее количество входов',
  `total_orders` int DEFAULT '0' COMMENT 'Общее количество заказов',
  `total_yuan_bought` decimal(10,2) DEFAULT '0.00' COMMENT 'Общее количество купленных юаней',
  `total_referrals` int DEFAULT '0' COMMENT 'Общее количество рефералов',
  `calculation_count` int DEFAULT '0' COMMENT 'Количество расчетов цен',
  `last_calculation_date` timestamp NULL DEFAULT NULL COMMENT 'Last calculation date',
  PRIMARY KEY (`telegram_id`),
  KEY `idx_users_last_activity` (`last_activity`),
  KEY `idx_users_telegram_id` (`telegram_id`),
  KEY `idx_users_access_expires` (`access_expires_at`),
  KEY `idx_users_username` (`username`),
  KEY `idx_users_xp` (`xp`),
  KEY `idx_users_current_level` (`current_level`),
  KEY `idx_users_last_daily_login` (`last_daily_login`),
  KEY `idx_users_level` (`current_level`),
  KEY `idx_users_streak` (`login_streak`),
  KEY `idx_users_savings` (`total_savings`),
  KEY `idx_users_orders` (`total_orders`),
  KEY `idx_users_referrals` (`total_referrals`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `users`
--

LOCK TABLES `users` WRITE;
