--
-- Table structure for table `xp_history`
--

DROP TABLE IF EXISTS `xp_history`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `xp_history` (
  `id` int NOT NULL AUTO_INCREMENT,
  `telegram_id` bigint NOT NULL,
  `xp_amount` int NOT NULL COMMENT 'Amount of XP gained (can be negative)',
  `source` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Source of XP: order, yuan_purchase, referral, achievement',
  `source_id` int DEFAULT NULL COMMENT 'ID of the source (order_id, purchase_id, etc.)',
  `description` text COLLATE utf8mb4_unicode_ci COMMENT 'Optional description',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_telegram_id` (`telegram_id`),
  KEY `idx_source` (`source`),
  KEY `idx_created_at` (`created_at`),
  KEY `idx_xp_history_telegram` (`telegram_id`),
  KEY `idx_xp_history_source` (`source`),
  KEY `idx_xp_history_created` (`created_at`),
  CONSTRAINT `xp_history_ibfk_1` FOREIGN KEY (`telegram_id`) REFERENCES `users` (`telegram_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=183 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `xp_history`
--

LOCK TABLES `xp_history` WRITE;
/*!40000 ALTER TABLE `xp_history` DISABLE KEYS */;
