--
-- Table structure for table `yuan_purchases`
--

DROP TABLE IF EXISTS `yuan_purchases`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `yuan_purchases` (
  `id` int NOT NULL AUTO_INCREMENT,
  `telegram_id` bigint NOT NULL,
  `amount_rub` decimal(10,2) NOT NULL,
  `amount_cny` decimal(10,2) NOT NULL,
  `exchange_rate` decimal(8,4) NOT NULL,
  `favorable_rate` decimal(8,4) NOT NULL,
  `savings` decimal(10,2) DEFAULT '0.00',
  `status` enum('pending','completed','cancelled') COLLATE utf8mb4_unicode_ci DEFAULT 'pending',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `telegram_id` (`telegram_id`),
  KEY `created_at` (`created_at`),
  KEY `status` (`status`),
  KEY `idx_yuan_purchases_status` (`status`),
  KEY `idx_yuan_purchases_telegram_id_status` (`telegram_id`,`status`),
  KEY `idx_yuan_telegram_id` (`telegram_id`),
  KEY `idx_yuan_created_at` (`created_at`),
  KEY `idx_yuan_status` (`status`),
  KEY `idx_yuan_telegram_created` (`telegram_id`,`created_at`),
  KEY `idx_yuan_analytics` (`created_at`,`status`,`amount_cny`),
  CONSTRAINT `yuan_purchases_ibfk_1` FOREIGN KEY (`telegram_id`) REFERENCES `users` (`telegram_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=31 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
