/*!50003 DROP PROCEDURE IF EXISTS `UpdateUserStats` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'STRICT_TRANS_TABLES' */ ;
DELIMITER ;;
CREATE DEFINER=`gen_user`@`%` PROCEDURE `UpdateUserStats`(IN user_telegram_id BIGINT)
BEGIN
  DECLARE total_orders_count INT DEFAULT 0;
  DECLARE referrals_count INT DEFAULT 0;
  DECLARE yuan_purchases_count INT DEFAULT 0;
  DECLARE yuan_savings_amount DECIMAL(12,2) DEFAULT 0.00;
  DECLARE yuan_total_amount DECIMAL(12,2) DEFAULT 0.00;

  -- Считаем заказы
  SELECT COUNT(*) INTO total_orders_count FROM orders WHERE telegram_id = user_telegram_id;

  -- Считаем рефералов
  SELECT COUNT(*) INTO referrals_count FROM referrals WHERE referred_by = user_telegram_id;

  -- Считаем покупки юаней
  SELECT COUNT(*) INTO yuan_purchases_count FROM yuan_purchases WHERE telegram_id = user_telegram_id;

  -- Считаем общую сумму купленных юаней
  SELECT COALESCE(SUM(amount_cny), 0) INTO yuan_total_amount FROM yuan_purchases WHERE telegram_id = user_telegram_id;

  -- Обновляем статистику в таблице users
  UPDATE users 
  SET 
    total_orders = total_orders_count,
    total_referrals = referrals_count,
    total_yuan_bought = yuan_total_amount,
    last_activity = NOW()
  WHERE telegram_id = user_telegram_id;

END ;;
DELIMITER ;
